jQuery(document).ready(function(e){jQuery(document).on("click","#ccfef_elementor_review_dismiss",e=>{jQuery(".ccfef_elementor_review_notice").hide();const c=jQuery(e.target),o=c.data("nonce"),n=c.data("url");jQuery.ajax({type:"POST",url:n,data:{action:"ccfef_elementor_review_notice",ccfef_notice_dismiss:!0,nonce:o},success:e=>{c.closest(".elementor-control").remove()},error:(e,c,o)=>{console.log(o),console.log(c)}})})});